//! DCT constants and utility functions.

/// sqrt(2) constant used in DCT
pub const SQRT2: f32 = 1.41421356237;

/// 1/sqrt(2), used in inverse DCT to avoid division
pub const INV_SQRT2: f32 = 1.0 / 1.41421356237;

